/* it's important that all literal comments in this file do not use the single line variant otherwise it will not compile correctly */
export const VERTEX_SHADER = `precision highp float;
attribute vec2 position;
varying vec2 vUv;
void main() {
    vUv = position * 0.5 + 0.5;
    gl_Position = vec4(position, 0.0, 1.0);
}`;

/* --- BACKGROUND SHADER (Water Body) --- */
/* Renders the rolling ocean swells and sun glints. */
export const BACKGROUND_FRAGMENT_SHADER = `#ifdef GL_FRAGMENT_PRECISION_HIGH
precision highp float;
#else
precision mediump float;
#endif

varying vec2 vUv;
uniform float uTime;
uniform vec2 uResolution;
uniform float uQuality;
uniform vec3 uColorDeep;
uniform vec3 uColorShallow;

void main() {
    
    float speed = 1.2;
    float time = uTime * speed;
    
    
    
    float wave1 = sin(vUv.x * 8.0 - time) * 0.0285;
    float wave2 = sin(vUv.x * 15.0 - time * 0.6) * 0.014;
    float wave = wave1 + wave2;

    
    
    
    float threshold = 0.428 + wave; 

    if (threshold > vUv.y) {
        discard;
    }

    
    if (uQuality <= 4.0) {
        vec3 col = mix(uColorShallow, uColorDeep, 0.5);
        float edge = (vUv.y - threshold) < 0.015 ? 1.0 : 0.0;
        col = mix(col, vec3(1.0, 1.0, 1.0), edge * 0.5);
        gl_FragColor = vec4(col, 1.0);
    } else {
        
        
        float gradientY = clamp((vUv.y - threshold) / (1.0 - threshold), 0.0, 1.0);
        
        vec3 col = mix(uColorShallow, uColorDeep, gradientY);
        
        
        float edge = 1.0 - smoothstep(0.0, 0.028, vUv.y - threshold);
        col = mix(col, vec3(1.0, 1.0, 1.0), edge * 0.4);
        
        gl_FragColor = vec4(col, 1.0);
    }
}`;

/* --- FOREGROUND SHADER (Waves/Surges) --- */
/* Renders the active game waves as Foam/Whitecaps. */
export const FRAGMENT_SHADER = `#ifdef GL_FRAGMENT_PRECISION_HIGH
precision highp float;
#else
precision mediump float;
#endif

varying vec2 vUv;
uniform float uTime;
uniform vec2 uResolution;
uniform float uQuality;
uniform sampler2D uWaveMap; 
uniform vec3 uColorDeep;
uniform vec3 uColorShallow;
uniform vec3 uColorWaveDeep;  
uniform vec3 uColorWave;      


float hash(vec2 p) {
    p = mod(p, 512.0);
    return fract(sin(dot(p, vec2(127.1, 311.7))) * 43758.5453123);
}
float noise(vec2 p) {
    vec2 i = floor(p);
    vec2 f = fract(p);
    vec2 u = f*f*(3.0-2.0*f);
    return mix(mix(hash(i + vec2(0.0,0.0)), hash(i + vec2(1.0,0.0)), u.x),
               mix(hash(i + vec2(0.0,1.0)), hash(i + vec2(1.0,1.0)), u.x), u.y);
}

void main() {
    vec2 uv = vUv;
    
    
    
    vec2 waveUV = uv - vec2(0.0, 0.0285);
    float intensity = texture2D(uWaveMap, waveUV).r;
    
    
    float shadowOffset = 8.0 / uResolution.y; 
    float shadowIntensity = texture2D(uWaveMap, waveUV + vec2(0.0, shadowOffset)).r;
    
    
    if (0.01 > intensity && 0.01 > shadowIntensity) discard;
    
    
    vec3 bodyColor = uColorWaveDeep;
    vec3 foamColor = uColorWave;
    
    vec3 finalColor;
    float finalAlpha;
    
    
    if (uQuality <= 4.0) {
        float sharpFoam = intensity > 0.65 ? 1.0 : 0.0;
        finalColor = mix(bodyColor, foamColor, sharpFoam);
        finalAlpha = intensity > 0.05 ? 1.0 : 0.0;
    } else {
        
        
        float streakyNoise = noise(vec2(uv.x * 60.0, uv.y * 4.0 + uTime * 4.0));
        
        
        
        
        float foamThreshold = 0.5;
        float foamMix = smoothstep(foamThreshold, foamThreshold + 0.2, intensity);
        
        
        finalColor = mix(bodyColor, foamColor, foamMix);
        
        
        if (0.9 > foamMix) {
            finalColor += (streakyNoise - 0.5) * 0.15 * (1.0 - foamMix);
        }
        
        
        
        
        
        
        
        
        finalAlpha = smoothstep(0.02, 0.15, intensity);
    }
    
    
    
    
    
    
    
    float speed = 1.2;
    float time = uTime * speed;
    float wave1 = sin(uv.x * 8.0 - time) * 0.0285;
    float wave2 = sin(uv.x * 15.0 - time * 0.6) * 0.014;
    float wave = wave1 + wave2;
    float threshold = 0.428 + wave;
    
    
    
    
    float shoreFade = smoothstep(0.0, threshold + 0.05, uv.y);
    
    float screenFade = shoreFade;
    
    
    float waveAlpha = finalAlpha * screenFade;
    
    
    float shadowBaseAlpha = smoothstep(0.02, 0.15, shadowIntensity);
    
    float shadowAlpha = shadowBaseAlpha * 0.4 * screenFade;
    
    
    
    float outAlpha = waveAlpha + shadowAlpha * (1.0 - waveAlpha);
    
    
    
    
    
    
    
    vec3 outRGB = finalColor * waveAlpha; 
    
    gl_FragColor = vec4(outRGB, outAlpha);
}`;

/* Wave Sprite Vertex Shader (Standard quad) */
export const WAVE_VERTEX_SHADER = `attribute vec2 aPosition;
attribute vec2 aUv;
attribute float aAlpha; 

varying vec2 vUv;
varying float vAlpha;

void main() {
    vUv = aUv;
    vAlpha = aAlpha;
    gl_Position = vec4(aPosition, 0.0, 1.0);
}`;

/* --- BRUSH SHADER --- */
/* Spawns a new wave crest. */
/* Shape: Blue Pill with White Leading Edge */
export const WAVE_BRUSH_FRAGMENT_SHADER = `#ifdef GL_FRAGMENT_PRECISION_HIGH
precision highp float;
#else
precision mediump float;
#endif
varying vec2 vUv;
varying float vAlpha;

float sdRoundedBox(vec2 p, vec2 b, float r) {
    vec2 q = abs(p) - b;
    return length(max(q, 0.0)) + min(max(q.x, q.y), 0.0) - r;
}

void main() {
    vec2 p = vUv - 0.5;
    
    
    vec2 b = vec2(0.35, 0.15);
    float r = 0.05;
    float d = sdRoundedBox(p, b, r);
    
    float shape = 1.0 - smoothstep(0.0, 0.02, d);
    shape = clamp(shape, 0.0, 1.0);

    
    
    
    
    
    float foam = smoothstep(0.45, 0.24, vUv.y);
    
    
    
    float bodyFade = smoothstep(0.4, 0.7, vUv.y);
    float bodyBase = mix(0.45, 0.0, bodyFade);

    
    float intensity = mix(bodyBase, 1.0, foam);

    gl_FragColor = vec4(shape * intensity * vAlpha, 0.0, 0.0, 1.0);
}`;

/* --- SIMULATION SHADER --- */
/* Moves the waves down. */
export const SIMULATION_FRAGMENT_SHADER = `#ifdef GL_FRAGMENT_PRECISION_HIGH
precision highp float;
#else
precision mediump float;
#endif

uniform sampler2D uLastFrame;
uniform vec2 uResolution;
uniform float uDt;

void main() {
    vec2 uv = gl_FragCoord.xy / uResolution;
    
    
    
    float resRatio = uResolution.y / 512.0;
    vec2 flow = vec2(0.0, (685.0 * resRatio * uDt) / uResolution.y); 
    
    vec2 sourceUv = uv + flow;

    if (sourceUv.y > 1.0) {
        gl_FragColor = vec4(0.0);
        return;
    }
    
    vec4 center = texture2D(uLastFrame, sourceUv);
    
    
    
    
    float decay = pow(0.99, uDt * 60.0);
    
    gl_FragColor = center * decay;
}`;
