// js/util/numFormat.js
// Policy:
//  - < 1e6: plain integer using the user's locale (grouping)
//  - 1e6 .. < 1e303: suffix table ("M,B,T,Qd,...") with FOUR visible digits
//  - >= 1e303: scientific, but with a pretty *recursive* exponent
//
// Also prettifies the exponent itself (e.g., 1.000e1,000 / e1.000Qd / e1.000e308)

import { BigNum, approxLog10BigNum } from './bigNum.js';

let currentNumberNotation = 'Standard';

export function setNumberNotation(notation) {
  currentNumberNotation = notation;
}

export function getNotationMode(E, notation = currentNumberNotation) {
  if (E < 6) return 'Standard';
  if (notation === 'Standard') return 'Standard';
  if (notation === 'Extended Suffixes') return 'Extended Suffixes';
  if (notation === 'Scientific (1e6+)') return E >= 6 ? 'Scientific' : 'Standard';
  if (notation === 'Scientific (1e33+)') return E >= 33 ? 'Scientific' : 'Standard';
  if (notation === 'Engineering (1e6+)') return E >= 6 ? 'Engineering' : 'Standard';
  if (notation === 'Engineering (1e33+)') return E >= 33 ? 'Engineering' : 'Standard';
  return 'Standard';
}


const EXT_SUFFIX_UNITS = ['', 'U', 'D', 'T', 'Qd', 'Qn', 'Sx', 'Sp', 'Oc', 'No'];
const EXT_SUFFIX_TENS = ['', 'De', 'Vt', 'Tg', 'qg', 'Qg', 'sg', 'Sg', 'Og', 'Ng'];
const EXT_SUFFIX_HUNDREDS = ['', 'Ce', 'Dn', 'Tc', 'Qe', 'Qu', 'Sc', 'St', 'Oe', 'Ne'];
const EXT_SUFFIX_TIERS = ['', 'Mi', 'Mc', 'Na', 'Pc', 'Fm', 'At', 'Zp', 'Yc', 'Xn', 'Ve', 'Me'];

function getAbbreviation(illion) {
  if (illion === 0) return '';
  const u = illion % 10;
  const t = Math.floor(illion / 10) % 10;
  const h = Math.floor(illion / 100) % 10;
  return EXT_SUFFIX_UNITS[u] + EXT_SUFFIX_TENS[t] + EXT_SUFFIX_HUNDREDS[h];
}

function getExtendedSuffix(illion) {
  if (illion === 0) return '';
  
  let result = '';
  let tier = 0;
  let remaining = illion;
  
  while (remaining > 0) {
    const chunk = remaining % 1000;
    remaining = Math.floor(remaining / 1000);
    
    if (chunk > 0) {
      let chunkSuffix = getAbbreviation(chunk);
      
      if (tier > 0) {
        if (chunk === 1) {
          chunkSuffix = ''; // For 1*1000^x, use 'Mi' instead of 'UMi'
        }
        
        if (tier < EXT_SUFFIX_TIERS.length) {
          chunkSuffix += EXT_SUFFIX_TIERS[tier];
        } else {
          chunkSuffix += getAbbreviation(tier);
        }
      }
      
      result = chunkSuffix + result;
    }
    tier++;
  }
  
  return result;
}

// Suffixes copied from CCC (descending exponents).
const SUFFIX_ENTRIES = [
  [300,'NoNg'],[297,'OcNg'],[294,'SpNg'],[291,'SxNg'],[288,'QnNg'],[285,'QdNg'],[282,'TNg'],[279,'DNg'],[276,'UNg'],[273,'Ng'],
  [270,'NoOg'],[267,'OcOg'],[264,'SpOg'],[261,'SxOg'],[258,'QnOg'],[255,'QdOg'],[252,'TOg'],[249,'DOg'],[246,'UOg'],[243,'Og'],
  [240,'NoSg'],[237,'OcSg'],[234,'SpSg'],[231,'SxSg'],[228,'QnSg'],[225,'QdSg'],[222,'TSg'],[219,'DSg'],[216,'USg'],[213,'Sg'],
  [210,'Nosg'],[207,'Ocsg'],[204,'Spsg'],[201,'Sxsg'],[198,'Qnsg'],[195,'Qdsg'],[192,'Tsg'],[189,'Dsg'],[186,'Usg'],[183,'sg'],
  [180,'NoQg'],[177,'OcQg'],[174,'SpQg'],[171,'SxQg'],[168,'QnQg'],[165,'QdQg'],[162,'TQg'],[159,'DQg'],[156,'UQg'],[153,'Qg'],
  [150,'Noqg'],[147,'Ocqg'],[144,'Spqg'],[141,'Sxqg'],[138,'Qnqg'],[135,'Qdqg'],[132,'Tqg'],[129,'Dqg'],[126,'Uqg'],[123,'qg'],
  [120,'NoTg'],[117,'OcTg'],[114,'SpTg'],[111,'SxTg'],[108,'QnTg'],[105,'QdTg'],[102,'TTg'],[99,'DTg'],[96,'UTg'],[93,'Tg'],
  [90,'NoVt'],[87,'OcVt'],[84,'SpVt'],[81,'SxVt'],[78,'QnVt'],[75,'QdVt'],[72,'TVt'],[69,'DVt'],[66,'UVt'],[63,'Vt'],
  [60,'NoDe'],[57,'OcDe'],[54,'SpDe'],[51,'SxDe'],[48,'QnDe'],[45,'QdDe'],[42,'TDe'],[39,'DDe'],[36,'UDe'],[33,'De'],
  [30,'No'],[27,'Oc'],[24,'Sp'],[21,'Sx'],[18,'Qn'],[15,'Qd'],[12,'T'],[9,'B'],[6,'M']
];
const SUFFIX_BY_EXP = new Map(SUFFIX_ENTRIES);

const NF_INT = new Intl.NumberFormat(undefined, { maximumFractionDigits: 0, useGrouping: true });
function localeInt(s) {
  const num = Number(s);

  // Safari throws a RangeError when formatting non-finite values via Intl.NumberFormat;
  // treat them as plain strings instead so the UI doesn't silently break on mobile.
  if (!Number.isFinite(num)) return String(s);

  try { return NF_INT.format(num); }
  catch { return String(s); }
}

// --- add 1 to a decimal digit-string (for rounding) ---
function addOneDigitString(str){
  let carry = 1, a = str.split('');
  for (let i = a.length - 1; i >= 0 && carry; i--) {
    let d = a[i].charCodeAt(0) - 48 + carry;
    carry = d >= 10 ? 1 : 0;
    a[i] = String.fromCharCode(48 + (d % 10));
  }
  if (carry) a.unshift('1');
  return a.join('');
}


function formatExponentString(rawDigits, sign = '') {
  let ds = (rawDigits || '').replace(/^0+/, '') || '0';

  if (ds.length < 4) return sign + localeInt(ds);          // < 1,000
  if (ds.length <= 7) {                                     // 1,000 .. <1,000,000
    const n = Number(ds);
    if (Number.isFinite(n) && n < 1_000_000) return sign + NF_INT.format(n);
  }

  const E = ds.length - 1;
  const mode = getNotationMode(E);

  if (mode === 'Standard') {
    if (E <= 300) {
      const exp = Math.floor(E / 3) * 3;
      const suffix = SUFFIX_BY_EXP.get(exp) || '';
      const d = E - exp;              // 0..2
      const intDigits = d + 1;        // 1..3
      const decimals = 4 - intDigits; // to keep FOUR visible digits
      const totalDigits = intDigits + decimals;

      if (ds.length < totalDigits + 1) ds += '0'.repeat(totalDigits + 1 - ds.length);
      let head = ds.slice(0, totalDigits);
      const nextDigit = ds.charCodeAt(totalDigits) || 48;

      let intStr, fracStr;
      if (head.length > totalDigits) {
        const newE = E + 1;
        const newExp = Math.floor(newE / 3) * 3;
        const newSuffix = SUFFIX_BY_EXP.get(newExp) || '';
        const newD = newE - newExp;
        const newIntDigits = newD + 1;
      const newDecimals = totalDigits - newIntDigits;
        const newHead = '1' + '0'.repeat(totalDigits - 1);
        intStr = newHead.slice(0, newIntDigits);
        fracStr = newHead.slice(newIntDigits);
        return sign + `${intStr}${newDecimals ? '.' + fracStr : ''}${newSuffix}`;
      } else {
        intStr = head.slice(0, intDigits);
        fracStr = head.slice(intDigits);
      }

      return sign + `${intStr}${decimals ? '.' + fracStr : ''}${suffix}`;
    }
  } else if (mode === 'Engineering') {
    const exp = Math.floor(E / 3) * 3;
    const d = E - exp;
    const intDigits = d + 1;
    const decimals = 4 - intDigits;
    const totalDigits = intDigits + decimals;

    if (ds.length < totalDigits + 1) ds += '0'.repeat(totalDigits + 1 - ds.length);
    let head = ds.slice(0, totalDigits);
    const nextDigit = ds.charCodeAt(totalDigits) || 48;
    // if (nextDigit >= 53) head = addOneDigitString(head); // Floor instead of round

    let intStr, fracStr, finalExpStr;
    if (head.length > totalDigits) { 
      // Carry overflow
      const newE = E + 1;
      const newExp = Math.floor(newE / 3) * 3;
      const newD = newE - newExp;
      const newIntDigits = newD + 1;
      const newDecimals = 4 - newIntDigits;
      const newHead = "1000";
      intStr = newHead.slice(0, newIntDigits);
      fracStr = newHead.slice(newIntDigits);
      finalExpStr = formatExponentString(String(newExp));
      return sign + `${intStr}${newDecimals ? '.' + fracStr : ''}e${finalExpStr}`;
    } else { 
      intStr = head.slice(0, intDigits); 
      fracStr = head.slice(intDigits); 
    }
    return sign + `${intStr}${decimals ? '.' + fracStr : ''}e${formatExponentString(String(exp))}`;
  }

  // Beyond our table (or Scientific notation within bounds): show scientific-within-exponent with FOUR-digit mantissa
  const totalDigits = 4; // 1 integer + 3 decimals
  if (ds.length < totalDigits + 1) ds += '0'.repeat(totalDigits + 1 - ds.length);
  let head = ds.slice(0, totalDigits);
  const nextDigit = ds.charCodeAt(totalDigits) || 48;
  // if (nextDigit >= 53) head = addOneDigitString(head); // Floor instead of round

  let finalE = E;
  if (head.length > totalDigits) {
    head = "1000";
    finalE++;
  }

  const mantInt  = head.slice(0, 1);
  const mantFrac = head.slice(1);
  return sign + `${mantInt}.${mantFrac}e` + formatExponentString(String(finalE));
}


function formatPowerOf10Exponent(kDigits, sign = '') {
  // Fast path to detect k ≥ 303 
  let ge303 = false, k = 0;
  if (kDigits.length > 3) ge303 = true;
  else { k = parseInt(kDigits || '0', 10) || 0; ge303 = (k >= 303); }

  if (ge303) {
    // Scientific inside exponent; pretty-format k itself (locale + suffix rules)
    return sign + '1.000e' + formatExponentString(kDigits);
  }

  // 0..302 → suffix tier plus remainder-driven mantissa
  const exp = Math.floor(k / 3) * 3;          // 0,3,6,...,300
  const suffix = SUFFIX_BY_EXP.get(exp) || '';

  const remainder = k - exp;                   // 0,1,2
  // FOUR visible digits before the suffix:
  //  r=0 → "1.000", r=1 → "10.00", r=2 → "100.0"
  const intPart   = (remainder === 0) ? '1' : (remainder === 1) ? '10' : '100';
  const decimals  = 4 - (remainder + 1);      // 3,2,1
  const fracPart  = decimals ? ('.' + '0'.repeat(decimals)) : '';

  return sign + intPart + fracPart + suffix;
}


function formatExponentChain(expRaw) {
  expRaw = String(expRaw).trim();

  // Optional leading sign on the whole exponent; suppress '+'
  let topSign = '';
  if (expRaw[0] === '+' || expRaw[0] === '-') {
    topSign = (expRaw[0] === '-') ? '-' : '';
    expRaw = expRaw.slice(1);
  }

  // Case A: pure digits (e.g., "...e305") → delegate to our big-int pretty printer
  if (/^\d+$/.test(expRaw)) return topSign + formatExponentString(expRaw);

  // Case B: scientific inside the exponent: "m e ± k"
  const m = expRaw.match(/^(\d+)(?:\.(\d+))?e([+-]?)(\d+)$/i);
  if (!m) return topSign + expRaw; // unknown form → keep as-is

  const [, int, frac = '', sign2, kDigits] = m;

  // Is k >= 303? (length check avoids unsafe parse)
  let kGe303 = false, k = 0;
  if (kDigits.length > 3) kGe303 = true;
  else { k = parseInt(kDigits || '0', 10) || 0; kGe303 = (k >= 303); }

  // First, compute a FOUR-digit mantissa from m (rounded)
  // We'll shift the decimal by (k % 3) for suffix-tiers.
  let ds = (int + frac).replace(/^0+/, '') || '0';
  if (ds.length < 5) ds += '0'.repeat(5 - ds.length);
  let four = ds.slice(0, 4);
  const next = ds.charCodeAt(4) || 48;
  // if (next >= 53) four = addOneDigitString(four); // handle rounding carry later // Floor instead of round
  
  // Account for overflow locally for format calc
  let localK = k;
  if (four.length > 4) {
    localK++;
  }
  
  const mode = getNotationMode(localK);

  if (kGe303 || mode === 'Scientific') {
    // Beyond our suffix table inside the exponent → scientific-of-exponent
    // Keep the (rounded) exponent mantissa ("3.617") and pretty-format k itself.
    if (four.length > 4) {
      four = "1000";
    }
    const mant = four.slice(0,1) + '.' + four.slice(1);
    const sign2Prefix = (sign2 === '-') ? '-' : '';
    return topSign + mant + 'e' + formatExponentString(localK > k ? String(localK) : kDigits, sign2Prefix);
  } else if (mode === 'Engineering') {
    const exp = Math.floor(localK / 3) * 3;
    const remainder = localK - exp;
    const intDigits = remainder + 1;
    const decimals = 4 - intDigits;
    
    let intStr, fracStr;
    if (four.length > 4) {
        four = "1000";
    }
    intStr = four.slice(0, intDigits);
    fracStr = four.slice(intDigits);
    
    const sign2Prefix = (sign2 === '-') ? '-' : '';
    return topSign + sign2Prefix + intStr + (decimals ? ('.' + fracStr) : '') + 'e' + formatExponentString(String(exp));
  }

  // Within our suffix table: choose suffix and place the decimal based on remainder
  const exp = Math.floor(k / 3) * 3;          // 0,3,6,...,300
  const suffix = SUFFIX_BY_EXP.get(exp) || '';
  const remainder = k - exp;                   // 0,1,2

  // Shift decimal: r=0 → "1.234", r=1 → "12.34", r=2 → "123.4"
  const intDigits = remainder + 1;             // 1..3
  const decimals  = 4 - intDigits;             // 3..1
  let intStr, fracStr;
  if (four.length > 4) { // carry overflow
    const newK = k + 1;
    const newExp = Math.floor(newK / 3) * 3;
    const newSuffix = SUFFIX_BY_EXP.get(newExp) || '';
    const newRemainder = newK - newExp;
    const newIntDigits = newRemainder + 1;
      const newDecimals = 4 - newIntDigits;
    const newFour = "1000";
    intStr = newFour.slice(0, newIntDigits);
    fracStr = newFour.slice(newIntDigits);
    const sign2Prefix = (sign2 === '-') ? '-' : '';
    return topSign + sign2Prefix + intStr + (newDecimals ? ('.' + fracStr) : '') + newSuffix;
  } else {
    intStr = four.slice(0, intDigits);
    fracStr = four.slice(intDigits);
  }

  const sign2Prefix = (sign2 === '-') ? '-' : '';
  return topSign + sign2Prefix + intStr + (decimals ? ('.' + fracStr) : '') + suffix;
}


 /* Ensures the mantissa is always  4 digits */
function mantissaFourDigits(sci) {
  const i = sci.toLowerCase().indexOf('e');
  if (i < 0) return sci;

  const rawMant = sci.slice(0, i);           // e.g., "3.2", "12.34" (should be 1.x form from toScientific)
  const rawExp = sci.slice(i + 1);

  if (!rawMant) {
    return 'e' + formatExponentChain(rawExp);
  }

  // --- Normalize mantissa to exactly 4 significant digits (1.xxx) with rounding ---
  // Build digit string (no dot)
  let ds = rawMant.replace('.', '');
  if (!/^\d+$/.test(ds)) return sci;         // safety: if parsing failed, bail out

  // Pad to at least 5 digits (4 kept + 1 for rounding)
  if (ds.length < 5) ds += '0'.repeat(5 - ds.length);

  // First 4 digits are kept (rounded by the 5th)
  let head = ds.slice(0, 4);
  const next = ds.charCodeAt(4) || 48;       // '0' if missing
  // if (next >= 53) head = addOneDigitString(head); // Floor instead of round

  // If carry overflow happened (e.g., 9.999 -> 10.00), re-normalize to 1.xxx by shifting
  let finalExp = rawExp;
  if (head.length > 4) {
    head = "1000"; // head is now "1000" after carry; that still prints as "1.000" below
    // increment exponent
    let m = finalExp.match(/^([+-]?)(\d+)$/);
    if (m) {
      finalExp = m[1] + (parseInt(m[2], 10) + 1).toString();
    }
  }

  const mantissa = head.slice(0,1) + '.' + head.slice(1); // "1.234" style with trailing zeros preserved

  // --- Pretty-format the exponent tail (can be "305" or "1e+100" etc.) ---
  return mantissa + 'e' + formatExponentChain(finalExp);
}

// Public API

function _formatNumber(bn) {
  if (!(bn instanceof BigNum)) return String(bn);
  if (bn.isNaN && bn.isNaN()) return 'NaN';
  if (bn.isInfinite && bn.isInfinite()) return '<span class="infinity-symbol">∞</span>';
  if (bn.isZero()) return '0';

  const E = bn.decExp ?? (bn.e + (bn.p - 1)); // decimal exponent

  // Plain integers < 1e6 → locale grouping
  if (E < 6) {
    return localeInt(bn.toPlainIntegerString());
  }
  
  const mode = getNotationMode(E);

  // Scientific for >= 1e303 (but pretty-print the exponent chain)
  if (mode === 'Scientific' || (mode === 'Standard' && E >= 303)) {
    return mantissaFourDigits(bn.toScientific(4));
  } else if (mode === 'Engineering') {
	if (E >= 1000000) {
      return mantissaFourDigits(bn.toScientific(4));
    }
    const exp = Math.floor(E / 3) * 3;
    const d = E - exp;                 // 0..2
    const intDigits = d + 1;           // 1..3
    const decimals  = 4 - intDigits;   // make FOUR visible digits
    const totalDigits = intDigits + decimals;

    let s = bn.sig.toString().padStart(bn.p, '0');
    if (s.length < totalDigits + 1) s += '0'.repeat(totalDigits + 1 - s.length);

    let head = s.slice(0, totalDigits);
    const nextDigit = s.charCodeAt(totalDigits) || 48;
    // if (nextDigit >= 53) head = addOneDigitString(head); // Floor instead of round

    let intStr, fracStr;
    if (head.length > totalDigits) {
      const newE = E + 1;
      const newExp = Math.floor(newE / 3) * 3;
      const newD = newE - newExp;
      const newIntDigits = newD + 1;
      const newDecimals = 4 - newIntDigits;
      
      const newHead = "1000";
      intStr = newHead.slice(0, newIntDigits);
      fracStr = newHead.slice(newIntDigits);
      return `${intStr}${newDecimals ? '.' + fracStr : ''}e${formatExponentString(String(newExp))}`;
    }
    else { 
      intStr = head.slice(0, intDigits); 
      fracStr = head.slice(intDigits); 
    }

    return `${intStr}${decimals ? '.' + fracStr : ''}e${formatExponentString(String(exp))}`;
  }

  if (mode === 'Extended Suffixes') {
    const exp = Math.floor(E / 3) * 3;
    const illion = Math.floor(E / 3) - 1;
    const suffix = illion < 100 ? SUFFIX_BY_EXP.get(exp) : getExtendedSuffix(illion);
    
    const d = E - exp;                 // 0..2
    const intDigits = d + 1;           // 1..3
    const decimals  = 4 - intDigits;   // make FOUR visible digits
    const totalDigits = intDigits + decimals;

    let s = bn.sig.toString().padStart(bn.p, '0');
    if (s.length < totalDigits + 1) s += '0'.repeat(totalDigits + 1 - s.length);

    let head = s.slice(0, totalDigits);
    const nextDigit = s.charCodeAt(totalDigits) || 48;
    // if (nextDigit >= 53) head = addOneDigitString(head); // Floor instead of round

    let intStr, fracStr;
    if (head.length > totalDigits) {
      const newE = E + 1;
      const newExp = Math.floor(newE / 3) * 3;
      const newIllion = Math.floor(newE / 3) - 1;
      const newSuffix = newIllion < 100 ? SUFFIX_BY_EXP.get(newExp) : getExtendedSuffix(newIllion);
      
      const newD = newE - newExp;
      const newIntDigits = newD + 1;
      const newDecimals = 4 - newIntDigits;
      
      const newHead = "1000";
      intStr = newHead.slice(0, newIntDigits);
      fracStr = newHead.slice(newIntDigits);
      return E >= 1000000 ? newSuffix : `${intStr}${newDecimals ? '.' + fracStr : ''}${newSuffix}`;
    }
    else { 
      intStr = head.slice(0, intDigits); 
      fracStr = head.slice(intDigits); 
    }

    return E >= 1000000 ? suffix : `${intStr}${decimals ? '.' + fracStr : ''}${suffix}`;
  }

  // Suffix formatting using the legacy table
  const exp = Math.floor(E / 3) * 3;
  const suffix = SUFFIX_BY_EXP.get(exp);
  if (!suffix) return mantissaFourDigits(bn.toScientific(4));

  const d = E - exp;                 // 0..2
  const intDigits = d + 1;           // 1..3
  const decimals  = 4 - intDigits;   // make FOUR visible digits
  const totalDigits = intDigits + decimals;

  let s = bn.sig.toString().padStart(bn.p, '0');
  if (s.length < totalDigits + 1) s += '0'.repeat(totalDigits + 1 - s.length);

  let head = s.slice(0, totalDigits);
  const nextDigit = s.charCodeAt(totalDigits) || 48;
  // if (nextDigit >= 53) head = addOneDigitString(head); // Floor instead of round

  let intStr, fracStr;
  if (head.length > totalDigits) {
    const newE = E + 1;
    const newExp = Math.floor(newE / 3) * 3;
    const newSuffix = SUFFIX_BY_EXP.get(newExp);
    if (!newSuffix) return mantissaFourDigits(bn.toScientific(4));
    
    const newD = newE - newExp;
    const newIntDigits = newD + 1;
      const newDecimals = 4 - newIntDigits;
    
    const newHead = "1000";
    intStr = newHead.slice(0, newIntDigits);
    fracStr = newHead.slice(newIntDigits);
    return `${intStr}${newDecimals ? '.' + fracStr : ''}${newSuffix}`;
  }
  else { 
    intStr = head.slice(0, intDigits); 
    fracStr = head.slice(intDigits); 
  }

  return `${intStr}${decimals ? '.' + fracStr : ''}${suffix}`;
}


export function formatNumber(bn, notationOverride = null) {
  if (!notationOverride) return _formatNumber(bn);
  const old = currentNumberNotation;
  currentNumberNotation = notationOverride;
  try {
    return _formatNumber(bn);
  } finally {
    currentNumberNotation = old;
  }
}

export function formatMultForUi(value) {
  try {
    if (value && (value instanceof BigNum || value.toPlainIntegerString)) {
      const log10 = approxLog10BigNum(value);
      if (Number.isFinite(log10) && log10 < 3) {
        const approx = Math.pow(10, log10);
        return String(approx.toFixed(3))
          .replace(/\.0+$/, '')
          .replace(/(\.\d*?)0+$/, '$1');
      }
      return formatNumber(value);
    }

    const n = Number(value) || 0;
    if (Math.abs(n) < 1000) {
      return String(n.toFixed(3))
        .replace(/\.0+$/, '')
        .replace(/(\.\d*?)0+$/, '$1');
    }
    return formatNumber(BigNum.fromAny(n));
  } catch {
    return '1';
  }
}
